import React from 'react'
import Card from './Card'

const BookingCard = ({services}) => {
  return (
    <div>
      {
        services.length!==0?(services.map((service,index)=>(<Card key={index} service={service} /> ))):
                          (<div></div>)
      }
    </div>
  )
}

export default BookingCard
